```go
// bulkMigrateEntities sends entities to the target org via the bulk upsert endpoint,
// grouped by blueprint in batches of EntityBulkBatchSize.
// Entities in entitiesToCreate use upsert=false (retries 409s with upsert=true).
// Entities in entitiesToUpdate use upsert=true directly.
func bulkMigrateEntities(
	ctx context.Context,
	client *api.Client,
	entities []api.Entity,
	entitiesToCreate map[string]bool,
	entitiesToUpdate map[string]bool,
	result *MigrateResult,
	mu *sync.Mutex,
) {
	type batchJob struct {
		blueprint string
		chunk     []api.Entity
		upsert    bool
	}

	byBlueprintCreate := make(map[string][]api.Entity)
	byBlueprintUpdate := make(map[string][]api.Entity)

	for _, entity := range entities {
		blueprintID, ok1 := entity["blueprint"].(string)
		entityID, ok2 := entity["identifier"].(string)
		if !ok1 || !ok2 || blueprintID == "" || entityID == "" {
			continue
		}
		key := fmt.Sprintf("%s:%s", blueprintID, entityID)
		if entitiesToCreate[key] {
			byBlueprintCreate[blueprintID] = append(byBlueprintCreate[blueprintID], entity)
		} else if entitiesToUpdate[key] {
			byBlueprintUpdate[blueprintID] = append(byBlueprintUpdate[blueprintID], entity)
		}
	}

	var jobs []batchJob
	for bp, ents := range byBlueprintCreate {
		for start := 0; start < len(ents); start += import_module.EntityBulkBatchSize {
			end := start + import_module.EntityBulkBatchSize
			if end > len(ents) {
				end = len(ents)
			}
			jobs = append(jobs, batchJob{blueprint: bp, chunk: ents[start:end], upsert: false})
		}
	}
	for bp, ents := range byBlueprintUpdate {
		for start := 0; start < len(ents); start += import_module.EntityBulkBatchSize {
			end := start + import_module.EntityBulkBatchSize
			if end > len(ents) {
				end = len(ents)
			}
			jobs = append(jobs, batchJob{blueprint: bp, chunk: ents[start:end], upsert: true})
		}
	}

	pool := import_module.NewWorkerPool(import_module.EntityConcurrency)
	for _, job := range jobs {
		j := job
		pool.Go(func() {
			errs, err := client.BulkUpsertEntities(ctx, j.blueprint, j.chunk, j.upsert)
			if err != nil {
				mu.Lock()
				for _, e := range j.chunk {
					id, _ := e["identifier"].(string)
					result.Errors = append(result.Errors, fmt.Sprintf("Entity %s: %v", id, err))
				}
				mu.Unlock()
				return
			}
			errByID := make(map[string]api.BulkEntityError, len(errs))
			for _, be := range errs {
				errByID[be.Identifier] = be
			}
			created := 0
			var conflicts []api.Entity
			for _, entity := range j.chunk {
				id, _ := entity["identifier"].(string)
				if bErr, failed := errByID[id]; failed {
					if int(bErr.StatusCode) == 409 && !j.upsert {
						conflicts = append(conflicts, entity)
					} else {
						mu.Lock()
						result.Errors = append(result.Errors, fmt.Sprintf("Entity %s: %s", id, bErr.Message))
						mu.Unlock()
					}
				} else {
					created++
				}
			}
			updated := 0
			if len(conflicts) > 0 {
				retryErrs, retryErr := client.BulkUpsertEntities(ctx, j.blueprint, conflicts, true)
				if retryErr != nil {
					mu.Lock()
					for _, e := range conflicts {
						id, _ := e["identifier"].(string)
						result.Errors = append(result.Errors, fmt.Sprintf("Entity %s: %v", id, retryErr))
					}
					mu.Unlock()
				} else {
					rErrByID := make(map[string]api.BulkEntityError, len(retryErrs))
					for _, re := range retryErrs {
						rErrByID[re.Identifier] = re
					}
					for _, entity := range conflicts {
						id, _ := entity["identifier"].(string)
						if rErr, failed := rErrByID[id]; failed {
							mu.Lock()
							result.Errors = append(result.Errors, fmt.Sprintf("Entity %s: %s", id, rErr.Message))
							mu.Unlock()
						} else {
							updated++
						}
					}
				}
			}
			mu.Lock()
			if j.upsert {
				result.EntitiesUpdated += created // upsert=true: creates are actually updates
			} else {
				result.EntitiesCreated += created
			}
			result.EntitiesUpdated += updated
			mu.Unlock()
		})
	}
	pool.Wait()
}
```

