	assert.Equal(t, 1, phase1, "Phase 1 uses upsert=false")
	assert.Equal(t, 1, phase2, "Phase 2 uses upsert=true")

	assert.Equal(t, 2, result.EntitiesCreated)

	// Phase names must match what users see in the terminal — do not change these strings
	phaseNames := make(map[string]bool)
	for _, ev := range progressEvents {
		phaseNames[ev.phase] = true
	}
	assert.True(t, phaseNames["Entities Phase 1"], "progress must report 'Entities Phase 1'")
	assert.True(t, phaseNames["Entities Phase 2 (relations)"], "progress must report 'Entities Phase 2 (relations)'")
}
